mapper.select:
SELECT COALESCE(( SELECT COUNT(*) FROM sensor s
), 0) AS sensor_numbers, COALESCE(( SELECT COUNT(*) FROM sensor s WHERE s.status IN (1, 2)
), 0) AS abnormal_sensor_numbers, COALESCE(( SELECT COUNT(*) FROM inspection i INNER JOIN sensor s ON i.sensor_id = s.id WHERE i.data_status IN (2, 3) AND i.create_time >= CURDATE() AND i.create_time < DATE_ADD(CURDATE(), INTERVAL 1 DAY)
), 0) AS warnings, COALESCE(( SELECT COUNT(*) FROM task t WHERE t.status IN (0, 1)
), 0) AS underway_task, COALESCE(( SELECT SUM(cnt) FROM ( SELECT COUNT(*) AS cnt FROM task t WHERE t.status = 0 AND t.public_time < DATE_SUB(NOW(), INTERVAL 24 HOUR)
UNION ALL SELECT COUNT(*) AS cnt FROM task t WHERE t.status = 1 AND t.response_time < DATE_SUB(NOW(), INTERVAL 48 HOUR)
UNION ALL SELECT COUNT(*) AS cnt FROM task t WHERE t.status = 3
) overtime_counts ), 0) AS overtime_task

SELECT COALESCE(( SELECT COUNT(*) FROM repairman r
), 0) AS repairman_number, COALESCE(( SELECT COUNT(*) FROM task t WHERE t.status = 2 AND t.accomplish_time >= CURDATE() AND t.accomplish_time < DATE_ADD(CURDATE(), INTERVAL 1 DAY)
), 0) AS today_task_number, CAST(COALESCE(ROUND( 100 * ( SELECT COUNT(*) FROM task t WHERE t.status = 2
) / NULLIF(( SELECT COUNT(*) FROM task t
), 0) ), 0) AS SIGNED) AS task_rate, CAST(COALESCE(ROUND(( SELECT AVG(TIMESTAMPDIFF(HOUR, t.response_time, t.accomplish_time)) FROM task t WHERE t.status = 2 AND t.response_time IS NOT NULL AND t.accomplish_time IS NOT NULL
)), 0) AS SIGNED) AS average_time
